// ── 每键按键模式设置 ──
// 模式:0=长按(按下即按下,松开才释放) 1=单次点按 2=持续点按(按频率连发) 3=长按持续点按(前阈值时间内单次点按,之后转持续点按)
const KEY_BUTTONS = ['z','x','c','h','f2','extra1','extra2','extra3','extra4','up','down','left','right','w','a','s','d'];
const KEY_MODE_HOLD = 0;
const KEY_MODE_TAP = 1;
const KEY_MODE_CONTINUOUS = 2;
const KEY_MODE_LONGPRESS_CONT = 3;
const KEY_MODE_LABELS = [
    { cn: '长按', en: 'Hold' },
    { cn: '单次点按', en: 'Tap' },
    { cn: '持续点按', en: 'Continuous' },
    { cn: '长按连发', en: 'LP Rapid' }
];
const KEY_MODE_DEFAULT_FREQ = 10;       // Hz
const KEY_MODE_DEFAULT_THRESH = 500;    // ms
const KEY_MODE_MIN_FREQ = 1;
const KEY_MODE_MAX_FREQ = 60;
const KEY_MODE_MIN_THRESH = 50;
const KEY_MODE_MAX_THRESH = 5000;
const KEY_BUTTON_LABELS_CN = {
    z: 'Z 键', x: 'X 键', c: 'C 键',
    h: '回血键', f2: '重开键',
    extra1: '拓展1', extra2: '拓展2', extra3: '拓展3', extra4: '拓展4',
    up: '上方向', down: '下方向', left: '左方向', right: '右方向',
    w: 'W 键', a: 'A 键', s: 'S 键', d: 'D 键'
};
const KEY_BUTTON_LABELS_EN = {
    z: 'Z', x: 'X', c: 'C',
    h: 'Heal', f2: 'Restart',
    extra1: 'Extra1', extra2: 'Extra2', extra3: 'Extra3', extra4: 'Extra4',
    up: 'Up', down: 'Down', left: 'Left', right: 'Right',
    w: 'W', a: 'A', s: 'S', d: 'D'
};
let key_modes = {};
function init_key_modes() {
    for (const name of KEY_BUTTONS) {
        if (!key_modes[name] || typeof key_modes[name] !== 'object') {
            key_modes[name] = { mode: KEY_MODE_HOLD, freq: KEY_MODE_DEFAULT_FREQ, thresh: KEY_MODE_DEFAULT_THRESH };
        } else {
            if (typeof key_modes[name].mode !== 'number' || key_modes[name].mode < 0 || key_modes[name].mode > 3) key_modes[name].mode = KEY_MODE_HOLD;
            if (typeof key_modes[name].freq !== 'number' || key_modes[name].freq <= 0) key_modes[name].freq = KEY_MODE_DEFAULT_FREQ;
            if (typeof key_modes[name].thresh !== 'number' || key_modes[name].thresh < 0) key_modes[name].thresh = KEY_MODE_DEFAULT_THRESH;
        }
    }
}
init_key_modes();
function save_key_modes() { localStorage.setItem('ctrl_key_modes', JSON.stringify(key_modes)); }
function load_key_modes() {
    try {
        const saved = JSON.parse(localStorage.getItem('ctrl_key_modes'));
        if (saved && typeof saved === 'object') { key_modes = saved; init_key_modes(); }
    } catch(e) { init_key_modes(); }
}
function reset_key_modes() {
    key_modes = {};
    init_key_modes();
    save_key_modes();
}

