let cfg_all=JSON.parse(JSON.stringify(default_cfg));

function load_cfg_all() {
    try {
        const s = JSON.parse(localStorage.getItem(CFG_STORE_KEY));
        if (s) {
            if (s.stick) Object.assign(cfg_all.stick, s.stick);
            if (s.dpad) {
                if (s.dpad.current_style !== undefined) cfg_all.dpad.current_style = s.dpad.current_style;
                if (s.dpad.style0) Object.assign(cfg_all.dpad.style0, s.dpad.style0);
                if (s.dpad.style1) Object.assign(cfg_all.dpad.style1, s.dpad.style1);
            }
            if (s.dual) {
                if (s.dual.swap !== undefined) cfg_all.dual.swap = s.dual.swap;
                if (s.dual.stick) cfg_all.dual.stick = s.dual.stick;
                if (s.dual.dpad) cfg_all.dual.dpad = s.dual.dpad;
            }
        }
    } catch(e) {}
    mobile_2pad_swap = cfg_all.dual.swap ? 1 : 0;
}
function save_cfg_all() {
    cfg_all.dual.swap = !!mobile_2pad_swap;
    localStorage.setItem(CFG_STORE_KEY, JSON.stringify(cfg_all));
}

function init_dual_config() {
    if (!cfg_all.dual) {
        cfg_all.dual = JSON.parse(JSON.stringify(default_cfg.dual));
        save_cfg_all();
    }
}

