// ── 文本输入(隐藏 input + 累积发送) ──
function _charToKeyName(char){const kc=char.charCodeAt(0);if(kc>=65&&kc<=90)return char;if(kc>=97&&kc<=122)return char.toUpperCase();if(kc>=48&&kc<=57)return char;if(char===' ')return ' ';if(char==='\n'||char==='\r')return 'Enter';if(char==='\b'||kc===8)return 'Backspace';return char;}
function _releaseBatch(){if(_batchKeys.length>0){for(const key of _batchKeys)send_key(key,false);_batchKeys=[];}_batchActive=false;if(_batchTimeout){clearTimeout(_batchTimeout);_batchTimeout=null;}}
function _sendBatch(str){if(_batchActive)_releaseBatch();const chars=str.split('');const keyNames=chars.map(c=>_charToKeyName(c)).filter(Boolean);if(keyNames.length===0)return;if(keyNames.includes('Enter'))_sendingEnter=true;_batchKeys=keyNames;_batchActive=true;for(const key of keyNames)send_key(key,true);_batchTimeout=setTimeout(()=>{_releaseBatch();if(keyNames.includes('Enter'))_sendingEnter=false;},50);}
function _sendSingle(ch){const keyName=_charToKeyName(ch);if(!keyName)return;if(keyName==='Enter')_sendingEnter=true;send_key(keyName,true);setTimeout(()=>{send_key(keyName,false);if(keyName==='Enter')_sendingEnter=false;},50);}
function _processInputChar(ch){
    if(deep_editing_field){
        if(ch==='\n'||ch==='\r'){_applyDeepSetting(deep_editing_temp);deep_editing_field=null;deep_editing_temp=null;_closeSystemKeyboard();return;}
        if(ch==='\b'||ch.charCodeAt(0)===8){if(deep_editing_temp.length>0)deep_editing_temp=deep_editing_temp.slice(0,-1);return;}
        deep_editing_temp+=ch;return;
    }
    if(ch==='\b'||ch.charCodeAt(0)===8){
        if(_accumTimeout){clearTimeout(_accumTimeout);_accumTimeout=null;}
        if(_accumulating){
            if(_accumBuffer.length>0)_accumBuffer=_accumBuffer.slice(0,-1);
            else _accumulating=false;
            return;
        }
        _sendSingle('Backspace');return;
    }
    if(ch==='\n'||ch==='\r'){
        if(_accumTimeout){clearTimeout(_accumTimeout);_accumTimeout=null;}
        if(_accumulating){
            if(_accumBuffer.length>0)_sendBatch(_accumBuffer);
            _accumBuffer='';_accumulating=false;
            return;
        }
        _sendSingle('Enter');return;
    }
    const code=ch.charCodeAt(0);const isLower=(code>=97&&code<=122);const isUpper=(code>=65&&code<=90);
    if(isLower){
        if(_accumTimeout){clearTimeout(_accumTimeout);_accumTimeout=null;}
        if(_accumulating){
            if(_accumBuffer.length>0)_sendBatch(_accumBuffer);
            _accumBuffer='';_accumulating=false;
        }
        _sendSingle(ch);
    }
    else if(isUpper){
        if(getVM()){
            // Scratch 环境:累积大写字母,2000ms 无新输入自动发送
            if(_accumTimeout){clearTimeout(_accumTimeout);_accumTimeout=null;}
            if(!_accumulating)_accumulating=true;
            _accumBuffer+=ch;
            _accumTimeout = setTimeout(() => {
                if(_accumBuffer.length>0){
                    _sendBatch(_accumBuffer);
                    _accumBuffer='';
                    _accumulating=false;
                }
                _accumTimeout=null;
            }, 2000);
        } else {
            // C2 环境:保持原有累积逻辑
            if(!_accumulating)_accumulating=true;
            _accumBuffer+=ch;
        }
    }
    else{
        if(_accumulating)_accumBuffer+=ch;
        else _sendSingle(ch);
    }
}
function _applyDeepSetting(val){
    if(!deep_editing_field) return;
    let target = deep_editing_field;
    if(target === 'mobile_f2' || target === 'mobile_heal' || target === 'mobile_2pad' || target === 'button_extra_1' || target === 'button_extra_2' || target === 'button_extra_3' || target === 'button_extra_4' || target === 'scr_button' || target === 'GreenFlag_Start' || target === 'Android_System_Keyboard' || target === 'mobile_cn'){
        let v = (val === '1' || val === 'true' || val === 'on') ? 1 : 0;
        eval(`${target}=${v}`);
        save_global_settings();
    }
    else if(target === 'mobile_f2_key' || target === 'mobile_heal_key' || target === 'button_extra_1_key' || target === 'button_extra_2_key' || target === 'button_extra_3_key' || target === 'button_extra_4_key'){
        let num = parseInt(val);
        if(!isNaN(num)) {
            eval(`${target}=${num}`);
            save_global_settings();
            update_keyboard_keymap();
        }
    }
    else if(target === 'button_c_key'){
        let num = parseInt(val);
        if(!isNaN(num)) {
            button_c_key = num;
            save_global_settings();
            update_keyboard_keymap();
        }
    }
    else if(target.startsWith('keymode_freq:') || target.startsWith('keymode_thresh:')) {
        const parts = target.split(':');
        const type = parts[0].substring('keymode_'.length);
        const name = parts[1];
        if(!key_modes[name]) key_modes[name] = { mode: KEY_MODE_HOLD, freq: KEY_MODE_DEFAULT_FREQ, thresh: KEY_MODE_DEFAULT_THRESH };
        let num = parseInt(val);
        if(!isNaN(num)) {
            if(type === 'freq') {
                num = Math.max(KEY_MODE_MIN_FREQ, Math.min(KEY_MODE_MAX_FREQ, num));
                key_modes[name].freq = num;
            } else if(type === 'thresh') {
                num = Math.max(KEY_MODE_MIN_THRESH, Math.min(KEY_MODE_MAX_THRESH, num));
                key_modes[name].thresh = num;
            }
            save_key_modes();
        }
    }
    else if(target.endsWith('_spr')){
        let testImg = new Image();
        testImg.onload = function(){
            eval(`${target}='${val}'`);
            save_global_settings();
        };
        testImg.onerror = function(){
            eval(`${target}='spr_space_button'`);
            save_global_settings();
        };
        testImg.src = mc_res_url(`MobileGraphics/${val}/${val}_0.png`);
        return;
    }
    else {
        save_global_settings();
        if(target.endsWith('_key')) update_keyboard_keymap();
    }
}
function _createHiddenInput(){
    if(_hidden_input)return;_hidden_input=document.createElement('input');_hidden_input.type='text';_hidden_input.style.cssText='position:fixed;left:-9999px;top:-9999px;opacity:0;width:1px;height:1px;';_hidden_input.setAttribute('inputmode','text');
    _hidden_input.addEventListener('input',function(){const val=_hidden_input.value;if(val.length>_lastInputValue.length){const newChars=val.slice(_lastInputValue.length);_hidden_input.value='';_lastInputValue='';for(const ch of newChars)_processInputChar(ch);}else if(val.length<_lastInputValue.length){const deletedCount=_lastInputValue.length-val.length;for(let i=0;i<deletedCount;i++)_processInputChar('\b');_lastInputValue=val;}else _lastInputValue=val;});
    _hidden_input.addEventListener('blur',function(){if(_kb_closing){system_kb_active=false;_kb_closing=false;return;}if(system_kb_active){setTimeout(()=>{if(system_kb_active&&_hidden_input&&!_kb_closing)_hidden_input.focus({preventScroll:true});},100);}});
    function handleGlobalPointerDown(e){if(!system_kb_active||!_hidden_input)return;if(e.target===_hidden_input)return;_closeSystemKeyboard();}
    document.addEventListener('mousedown',handleGlobalPointerDown,{passive:true,capture:true});document.addEventListener('touchstart',handleGlobalPointerDown,{passive:true,capture:true});document.body.appendChild(_hidden_input);
}
function _openSystemKeyboard(){if(!_hidden_input)_createHiddenInput();system_kb_active=true;setTimeout(()=>_hidden_input.focus({preventScroll:true}),50);}
function _closeSystemKeyboard(){if(!_hidden_input||!system_kb_active)return;_kb_closing=true;system_kb_active=false;_hidden_input.blur();setTimeout(()=>{_kb_closing=false;},200);}

// ── 绘制辅助函数(对应 GMS 的 draw_* 系列) ──
function gms_col(col) { if(col===undefined||col===0xFFFFFF) return 'rgba(255,255,255,1)'; const b=(col&0xFF)/255, g=((col>>8)&0xFF)/255, r=((col>>16)&0xFF)/255; return `rgba(${r*255},${g*255},${b*255},1)`; }
function fmt_num(v) { return Number.isInteger(v)?Math.round(v).toString():v.toFixed(2); }
let _draw_alpha=1;
function draw_set_alpha(a) { _draw_alpha=a; }
function draw_sprite_ext(sprite, subimg, x, y, xscale, yscale, rot, colour, alpha) {
    if(!sprite?.complete) return;
    ctx.save(); ctx.globalAlpha=_draw_alpha*alpha;
    ctx.drawImage(sprite, x, y, sprite.naturalWidth*xscale, sprite.naturalHeight*yscale);
    if(colour!==undefined&&colour!==c_white) { ctx.globalCompositeOperation='source-in'; ctx.fillStyle=gms_col(colour); ctx.fillRect(x, y, sprite.naturalWidth*xscale, sprite.naturalHeight*yscale); }
    ctx.restore();
}
function draw_colored(sprite, x, y, w, h, col, alpha) {
    const t=document.createElement('canvas'); t.width=Math.ceil(w); t.height=Math.ceil(h); const tc=t.getContext('2d'); tc.imageSmoothingEnabled=false;
    tc.drawImage(sprite,0,0,w,h); tc.globalCompositeOperation='source-atop'; tc.fillStyle=gms_col(col); tc.fillRect(0,0,w,h);
    ctx.save(); ctx.globalAlpha=alpha; ctx.drawImage(t,x,y); ctx.restore();
}
function draw_roundrect_color(x1,y1,x2,y2,col1,col2,outline) {
    const lx=Math.min(x1,x2), rx=Math.max(x1,x2), ty=Math.min(y1,y2), by=Math.max(y1,y2);
    const w=rx-lx, h=by-ty, r=Math.min(6,w/2,h/2);
    ctx.save(); ctx.globalAlpha=_draw_alpha; ctx.imageSmoothingEnabled=false;
    ctx.beginPath(); ctx.moveTo(lx+r,ty); ctx.lineTo(rx-r,ty); ctx.quadraticCurveTo(rx,ty,rx,ty+r); ctx.lineTo(rx,by-r); ctx.quadraticCurveTo(rx,by,rx-r,by); ctx.lineTo(lx+r,by); ctx.quadraticCurveTo(lx,by,lx,by-r); ctx.lineTo(lx,ty+r); ctx.quadraticCurveTo(lx,ty,lx+r,ty); ctx.closePath();
    if(outline) { ctx.strokeStyle=col2; ctx.lineWidth=1; ctx.stroke(); } else { ctx.fillStyle=col1; ctx.fill(); }
    ctx.restore();
}

